not specified."}, "resourceId": {"type": "string", "description": "(Required) The Radius PersistentVolume resource ID."}}, "description": "(Optional) Mount an existing Radius PersistentVolume resource."}}}}, "replicas": {"type": "integer", "description": "(Optional) The minimum number of replicas for the set of containers."}, "containers": {"type": "object", "additionalProperties": {"type": "object", "required": ["image"], "properties": {"env": {"type": "object", "description": "(Optional) Environment variables injected into the container.", "additionalProperties": {"type": "object", "properties": {"value": {"type": "string", "description": "(Optional) String value of the environment variable."}, "valueFrom": {"type": "object", "properties": {"secretKeyRef": {"type": "object", "properties": {"key": {"type": "string", "description": "(Optional) The key of the Radius Secrets resource. The value of the key will be used as the environment variable value."}, "secretName": {"type": "string", "description": "(Optional) The name of the Radius Secrets resource."}}, "description": "(Optional) Set the environment variable value based on a Radius Secrets resource."}}}}}}, "args": {"type": "array", "items": {"type": "string"}, "description": "(Optional) Arguments for the command. Overrides the container image CMD. `[\\"echo Hello\\", \\"&&\\", \\"echo World\\"]` for example."}, "image": {"type": "string", "description": "(Required) The container image. `ghcr.io/radius-project/samples/demo:latest` for example."}, "ports": {"type": "object", "description": "(Optional) Network ports exposed by the container. A network endpoint is created for each port. For L7 ingress create a Routes resource.", "additionalProperties": {"type": "object", "required": ["containerPort"], "properties": {"protocol": {"enum": ["TCP", "UDP"], "type": "string", "description": "(Optional) The protocol. If not specified, `TCP` is assumed."}, "containerPort": {"type": "integer", "description": "(Required) The network port the container is listening on. `443` for example."}}}}, "command": {"type": "array", "items": {"type": "string"}, "description": "(Optional) Command the container runs. Overrides the container image ENTRYPOINT. `[\\"/bin/sh\\", \\"-c\\"]` for example."}, "resources": {"type": "object", "properties": {"limits": {"type": "object", "properties": {"cpu": {"type": "string", "description": "(Optional) The maximum number of vCPUs which can be used by the container."}, "memoryInMib": {"type": "integer", "description": "(Optional) The maximum amount of memory which can be used by the container in MiB."}}, "description": "(Optional) Limits define the maximum amount of CPU or memory the container can consume."}, "requests": {"type": "object", "properties": {"cpu": {"type": "string", "description": "(Optional) The minimum number of vCPUs required by the container. `0.1` results in one tenth of a vCPU being reserved."}, "memoryInMib": {"type": "integer", "description": "(Optional) The minimum amount of memory required by the container in MiB. `1024` results in 1 GiB of memory being reserved."}}, "description": "(Optional) Requests define the minimum amount of CPU or memory that is required by the container."}}, "description": "(Optional) Compute resource requirements for the container."}, "workingDir": {"type": "string", "description": "(Optional) The working directory inside the container. `/usr/share` for example."}, "volumeMounts": {"type": "array", "items": {"type": "object", "required": ["volumeName", "mountPath"], "properties": {"mountPath": {"type": "string", "description": "(Required) The path to mount the volume in the container file system."}, "volumeName": {"type": "string", "description": "(Required) The name of the volume defined in Containers.properties.volumes."}}}, "description": "(Optional) Volumes to mount in the container."}, "initContainer": {"type": "boolean", "description": "(Optional) Set to true if container should run and succeed prior to other containers starting."}, "livenessProbe": {"type": "object", "properties": {"exec": {"type": "object", "required": ["command"], "properties": {"command": {"type": "array", "items": {"type": "string"}, "description": "(Required) The command to run inside the container. `[\\"cat\\", \\"/tmp/healthy\\"]` for example."}}, "description": "(Optional) An exec probe runs a command within a container. If the command succeeds and returns 0 the probe is healthy."}, "httpGet": {"type": "object", "required": ["path", "port"], "properties": {"path": {"type": "string", "description": "(Required) The path to access on the HTTP server."}, "port": {"type": "integer", "description": "(Required) The TCP port connect to on the container."}, "scheme": {"enum": ["http", "https"], "type": "string", "description": "(Optional) HTTP or HTTPS. Assumes HTTP is not specified."}, "httpHeaders": {"type": "array", "items": {"type": "object", "required": ["value"], "properties": {"value": {"type": "string", "description": "(Required) The header field value."}}}, "description": "(Optional) Custom HTTP headers to be included in the GET request."}}, "description": "(Optional) A httpGet probe performs a HTTP GET against the container on the specified port. If the HTTP server returns a code greater than or equal to 200 and less than 400 the probe is healthy."}, "tcpSocket": {"type": "object", "required": ["port"], "properties": {"port": {"type": "integer", "description": "(Required) The TCP port to connect to."}}, "description": "(Optional) A TCP socket probe establishes a TCP connection to the container on the specified port. If a connection is established the probe is healthy."}, "periodSeconds": {"type": "integer", "description": "(Optional) How often to perform the probe. Assumed to be 10 seconds if not specified."}, "timeoutSeconds": {"type": "integer", "description": "(Optional) Number of seconds after which the probe times out. Assumed to be 1 second if not specified."}, "failureThreshold": {"type": "integer", "description": "(Optional) Minimum consecutive failures for the probe to be considered failed after having succeeded. Assumed to be 3 if not specified."}, "successThreshold": {"type": "integer", "description": "(Optional) Minimum consecutive successes for the probe to be considered successful after having failed. Assumed to be 1 if not specified."}, "initialDelaySeconds": {"type": "integer", "description": "(Optional) Number of seconds after the container has started before probes are initiated."}, "terminationGracePeriodSeconds": {"type": "integer", "description": "(Optional) Number of seconds the container needs to terminate gracefully upon probe failure. The grace period amount of time between when a container is sent a termination signal and the time when the processes are forcibly halted with a kill signal."}}, "description": "(Optional) A liveness probe defines a check (a probe) to determine if a container is healthy."}, "readinessProbe": {"type": "object", "properties": {"exec": {"type": "object", "required": ["command"], "properties": {"command": {"type": "array", "items": {"type": "string", "description": "(Required) The command to run inside the container. `[\\"cat\\", \\"/tmp/healthy\\"]` for example."}}}, "description": "(Optional) An exec probe runs a command within a container. If the command succeeds and returns 0 the probe is healthy."}, "httpGet": {"type": "object", "required": ["path", "port"], "properties": {"path": {"type": "string", "description": "(Required) The path to access on the HTTP server."}, "port": {"type": "integer", "description": "(Required) The TCP port connect to on the container."}, "scheme": {"enum": ["http", "https"], "type": "string", "description": "(Optional) HTTP or HTTPS. Assumes HTTP is not specified."}, "httpHeaders": {"type": "array", "items": {"type": "object", "required": ["value"], "properties": {"value": {"type": "string", "description": "(Required) The header field value."}}}, "description": "(Optional) Custom HTTP headers to be included in the GET request."}}, "description": "(Optional) A httpGet probe performs a HTTP GET against the container on the specified port. If the HTTP server returns a code greater than or equal to 200 and less than 400 the probe is healthy."}, "tcpSocket": {"type": "object", "required": ["port"], "properties": {"port": {"type": "integer", "description": "(Required) The TCP port to connect to."}}, "description": "(Optional) A TCP socket probe establishes a TCP connection to the container on the specified port. If a connection is established the probe is healthy."}, "periodSeconds": {"type": "integer", "description": "(Optional) How often to perform the probe. Assumed to be 10 seconds if not specified."}, "timeoutSeconds": {"type": "integer", "description": "(Optional) Number of seconds after which the probe times out. Assumed to be 1 second if not specified."}, "failureThreshold": {"type": "integer", "description": "(Optional) Minimum consecutive failures for the probe to be considered failed after having succeeded. Assumed to be 3 if not specified."}, "successThreshold": {"type": "integer", "description": "(Optional) Minimum consecutive successes for the probe to be considered successful after having failed. Assumed to be 1 if not specified."}, "initialDelaySeconds": {"type": "integer", "description": "(Optional) Number of seconds after the container has started before probes are initiated."}, "terminationGracePeriodSeconds": {"type": "integer", "description": "(Optional) Number of seconds the container needs to terminate gracefully upon probe failure. The grace period amount of time between when a container is sent a termination signal and the time when the processes are forcibly halted with a kill signal."}}, "description": "(Optional) A readiness probe defines a check (a probe) to determine when a container is ready to begin accepting traffic."}}}}, "extensions": {"type": "object", "properties": {"daprSidecar": {"type": "object", "properties": {"appId": {"type": "string", "description": "(Optional) The unique ID of the Dapr application. Used for service discovery, state encapsulation and the pub/sub consumer ID."}, "config": {"type": "string", "description": "(Optional) The Dapr Configuration resource name."}, "appPort": {"type": "integer", "description": "(Optional) The port your application is listening on."}}, "description": "(Optional) When set the daprSidecar container is configured."}}, "description": "(Optional) Properties for additional functionality. daprSidecar is the only available option."}, "application": {"type": "string", "description": "(Required) The Radius Application ID. `myApplication.id` for example."}, "autoScaling": {"type": "object", "required": ["metrics"], "properties": {"metrics": {"type": "array", "items": {"type": "object", "required": ["kind", "target"], "properties": {"kind": {"enum": ["cpu", "memory", "custom"], "type": "string", "description": "(Required) The metric to measure."}, "target": {"type": "object", "properties": {"value": {"type": "integer", "description": "(Optional) The absolute value of the metric as a quantity."}, "averageValue": {"type": "integer", "description": "(Optional) The average value of the metric as a quantity."}, "averageUtilization": {"type": "integer", "description": "(Optional) The average CPU or memory utilization across all containers expressed as a percentage. Kind must be CPU or memory."}}, "description": "(Required) When the metric exceeds the target value specified, autoscaling is triggered. Only one target value can be specified dependent upon the type."}, "customMetric": {"type": "string", "description": "(Optional) The custom metric exposed by the application. Implementation specific. See platform engineer for further guidance."}}}, "description": "(Required) The metric to measure and target used to autoscale."}, "maxReplicas": {"type": "integer", "description": "(Optional) The maximum number of replicas for the autoscaler."}}}, "connections": {"type": "object", "description": "(Optional) Map of resources this container is dependent upon. `db: { source: db.id } for example.", "additionalProperties": {"type": "object", "required": ["source"], "properties": {"source": {"type": "string", "description": "(Required) The resource ID of the resource this container is dependent upon."}, "disableDefaultEnvVars": {"type": "boolean", "description": "(Optional) Disables the automatic injection of environment variables from connected resource properties."}}}}, "environment": {"type": "string", "description": "(Required) The Radius Environment ID. Typically set by the rad CLI. Typically value should be `environment`."}, "codeReference": {"type": "string", "description": "Optional URI to the source code of this resource type. ex: https://github.com/radius-project/radius/blob/4fab87e8127adf1db6f43b7029d5235fbe82c5c9/cmd/controller/main.go#L27"}, "restartPolicy": {"enum": ["Always", "OnFailure", "Never"], "type": "string", "description": "(Optional) Defines how a containers behave when they terminate. `Always` will restart containers regardless of their exit status. `OnFailure` will restart containers if they return a non-zero exit code."}, "platformOptions": {"type": "object", "description": "(Optional) If enabled by the platform engineer, properties to be passed to the Recipe for the specified platform.", "additionalProperties": {"type": "any", "description": "(Required) Platform-specific properties."}}}}}, "systemData": {}, "createdApiVersion": "", "provisioningState": "Succeeded"}
