/planes/radius/local/providers/system.resources/resourceproviders/radius.compute/resourcetypes/routes/	/planes/radius/local/providers/System.Resources/resourceProviders/Radius.Compute/resourceTypes/routes	/system.resources/resourceproviders/resourcetypes/	/planes/radius/local/	/system.resources/resourceproviders/radius.compute/resourcetypes/routes/	32-6c90df1a67e69f971270a610645a5d53f2adbffdcd37e1057bdb102c2f61f95b	2026-07-01 21:18:08.774578+00	{"id": "/planes/radius/local/providers/System.Resources/resourceProviders/Radius.Compute/resourceTypes/routes", "name": "routes", "type": "System.Resources/resourceProviders/resourceTypes", "location": "", "tenantId": "", "properties": {"description": "The Radius.Compute/routes Resource Type defines network routes for responding to external clients. Note that a Routes resource is not required for service-to-service communication. To use Routes, define a Container and ensure a `containerPort` is specified.\\n```\\nextension radius\\nparam environment string\\n\\nresource myApplication 'Radius.Core/applications@2025-08-01-preview' = { ... }\\n\\nresource myContainer 'Radius.Compute/containers@2025-08-01-preview' = {\\n  name: 'myContainer'\\n  properties: {\\n    environment: environment\\n    application: myApplication.id\\n    containers: {\\n      frontend: {\\n        image: 'frontend:1.25'\\n        ports: {\\n          web: {\\n            containerPort: 8080\\n          }\\n        }\\n      }\\n      accounts: {\\n        image: 'accounts:1.25'\\n        ports: {\\n          web: {\\n            containerPort: 8080\\n          }\\n        }\\n      }\\n    }\\n  }\\n}\\n```\\n\\nThen define a Routes resource.\\n```\\nresource ingressRule 'Radius.Compute/routes@2025-08-01-preview' = {\\n  name: 'ingressRule'\\n  properties: {\\n    application: myApplication.id\\n    environment: environment\\n    kind: 'HTTP'\\n    rules: [\\n      {\\n        matches: [\\n          {\\n            httpPath: '/'\\n          }\\n        ]\\n        destinationContainer: {\\n          resourceId: myContainer.id\\n          containerName: 'frontend'\\n          containerPort: myContainer.properties.containers.frontend.ports.web.containerPort\\n        }\\n      }\\n    ]\\n  }\\n}\\n```\\n\\nThe hostname is determined by the Recipe. \\n\\nMultiple rules can be included in Routes.\\n```\\nresource ingressRule 'Radius.Compute/routes@2025-08-01-preview' = {\\n  name: 'ingressRule'\\n  properties: {\\n    application: myApplication.id\\n    environment: environment\\n    kind: 'HTTP'\\n    rules: [\\n      {\\n        matches: [\\n          {\\n            httpPath: '/'\\n          }\\n        ]\\n        destinationContainer: {\\n          resourceId: myContainer.id\\n          containerName: 'frontend'\\n          containerPort: myContainer.properties.containers.frontend.ports.web.containerPort\\n        }\\n      }\\n      {\\n        matches: [\\n          {\\n            httpPath: '/accounts'\\n          }\\n        ]\\n        destinationContainer: {\\n          resourceId: myContainer.id\\n          containerName: 'accounts'\\n          containerPort: myContainer.properties.containers.accounts.ports.web.containerPort\\n        }\\n      }\\n    ]\\n  }\\n}\\n```\\n", "defaultApiVersion": null}, "systemData": {}, "createdApiVersion": "", "provisioningState": "Succeeded"}
/planes/radius/local/providers/system.resources/resourceproviders/radius.compute/resourcetypes/routes/apiversions/2025-08-01-preview/	/planes/radius/local/providers/System.Resources/resourceProviders/Radius.Compute/resourceTypes/routes/apiVersions/2025-08-01-preview	/system.resources/resourceproviders/resourcetypes/apiversions/	/planes/radius/local/	/system.resources/resourceproviders/radius.compute/resourcetypes/routes/apiversions/2025-08-01-preview/	32-e6b4d47ff33c07be6e65054d29a68f7abb6b8ef33d146c01188189f73c160ec4	2026-07-01 21:18:08.775098+00	{"id": "/planes/radius/local/providers/System.Resources/resourceProviders/Radius.Compute/resourceTypes/routes/apiVersions/2025-08-01-preview", "name": "2025-08-01-preview", "type": "System.Resources/resourceProviders/resourceTypes/apiVersions", "location": "", "tenantId": "", "properties": {"Schema": {"type": "object", "required": ["environment", "application", "rules"], "properties": {"kind": {"enum": ["HTTP", "TCP", "TLS", "UDP"], "type": "string", "description": "(Optional) The type of rule. If not specified, `HTTPRoute` is assumed. `HTTPRoute` provides L7 ingress with support for matching based on the hostname and HTTP header. `TCPRoute` provides L4 ingress with no support for matching (all traffic is forwarded to the Container). `TLSRoute` provides L4 ingress with the ability to match based on Server Name Indication (SNI) which is equivalent to hostname in TLS. `UDPRoute` is similar to TCPRoutes but uses UDP."}, "rules": {"type": "array", "items": {"type": "object", "required": ["matches", "destinationContainer"], "properties": {"matches": {"type": "array", "items": {"type": "object", "properties": {"httpPath": {"type": "string", "description": "(Optional) The HTTP request path to match. Trailing space is ignored. Requests for `/abc`, `/abc/`, and ``/abc/def/` will all match `/abc`."}, "httpMethod": {"enum": ["GET", "HEAD", "POST", "PUT", "DELETE", "CONNECT", "OPTIONS", "TRACE", "PATCH"], "type": "string", "description": "(Optional) The HTTP method to match. Specify only when kind is HTTP."}, "httpHeaders": {"type": "array", "items": {"type": "object", "required": ["name", "value"], "properties": {"name": {"type": "string", "description": "(Required) The name of the HTTP Header to be matched. Must be exact."}, "value": {"type": "string", "description": "(Required) Value of HTTP Header to be matched."}}}, "description": "(Optional) HTTP headers to match. Specify only when kind is HTTP. Multiple match values are ANDed together. A request must match all the specified headers to match."}, "httpQueryParams": {"type": "array", "items": {"type": "object", "required": ["name", "value"], "properties": {"name": {"type": "string", "description": "(Required) Name of the HTTP query parameter to be matched. Specify only when kind is HTTP."}, "value": {"type": "string", "description": "(Required) Value of the HTTP query parameter to be matched."}}}, "description": "(Optional) HTTP query parameters to match. Specify only when kind is HTTP."}}}, "description": "(Required) Matches define conditions used for matching a request."}, "destinationContainer": {"type": "object", "required": ["resourceId", "containerName", "containerPort"], "properties": {"resourceId": {"type": "string", "description": "(Required) The Radius Container resource ID."}, "containerName": {"type": "string", "description": "(Required) The specific container to target within the Container resource."}, "containerPort": {"type": "integer", "description": "(Required) The port to target from the container."}}}}}, "description": "(Required) Rules define semantics for matching a network connection request based on conditions and forwarding the request to a Container."}, "listener": {"type": "object", "readOnly": true, "properties": {"port": {"type": "integer"}, "hostname": {"type": "string"}, "protocol": {"enum": ["HTTP", "HTTPS", "TLS", "TCP", "UDP"], "type": "string"}}, "description": "(Read Only) The Gateway Listener the route is assigned to."}, "hostnames": {"type": "array", "items": {"type": "string"}, "description": "(Optional) Use only when kind is HTTP or TLS. When HTTP, match against the HTTP Host header. When using TLS, match against the SNI attribute of TLS ClientHello message. Hostname may be preceded by a * wildcard."}, "application": {"type": "string", "description": "(Required) The Radius Application ID. `myApplication.id` for example."}, "connections": {"type": "object", "description": "Map of connection name to connection data.", "additionalProperties": {"type": "object", "required": ["source"], "properties": {"source": {"type": "string", "description": "Resource ID of the source resource for this connection."}, "disableDefaultEnvVars": {"type": "boolean", "description": "Disables the automatic injection of environment variables from the connected resource's properties."}}}}, "environment": {"type": "string", "description": "(Required) The Radius Environment ID. Typically set by the rad CLI. Typically value should be `environment`."}, "codeReference": {"type": "string", "description": "Optional URI to the source code of this resource type. ex: https://github.com/radius-project/radius/blob/4fab87e8127adf1db6f43b7029d5235fbe82c5c9/cmd/controller/main.go#L27"}}}}, "systemData": {}, "createdApiVersion": "", "provisioningState": "Succeeded"}
