/planes/radius/local/providers/system.resources/resourceprovidersummaries/radius.compute/	/planes/radius/local/providers/System.Resources/resourceProviderSummaries/Radius.Compute	/system.resources/resourceprovidersummaries/	/planes/radius/local/	/system.resources/resourceprovidersummaries/radius.compute/	32-96d1815694a4b42eb090e0ee4601f22034090458d867fd83e32d8166d8fd5fe9	2026-07-01 21:18:08.776574+00	{"id": "/planes/radius/local/providers/System.Resources/resourceProviderSummaries/Radius.Compute", "name": "Radius.Compute", "type": "System.Resources/resourceProviderSummaries", "location": "", "tenantId": "", "properties": {"locations": {"global": {}}, "resourceTypes": {"routes": {"apiVersions": {"2025-08-01-preview": {"schema": {"type": "object", "required": ["environment", "application", "rules"], "properties": {"kind": {"enum": ["HTTP", "TCP", "TLS", "UDP"], "type": "string", "description": "(Optional) The type of rule. If not specified, `HTTPRoute` is assumed. `HTTPRoute` provides L7 ingress with support for matching based on the hostname and HTTP header. `TCPRoute` provides L4 ingress with no support for matching (all traffic is forwarded to the Container). `TLSRoute` provides L4 ingress with the ability to match based on Server Name Indication (SNI) which is equivalent to hostname in TLS. `UDPRoute` is similar to TCPRoutes but uses UDP."}, "rules": {"type": "array", "items": {"type": "object", "required": ["matches", "destinationContainer"], "properties": {"matches": {"type": "array", "items": {"type": "object", "properties": {"httpPath": {"type": "string", "description": "(Optional) The HTTP request path to match. Trailing space is ignored. Requests for `/abc`, `/abc/`, and ``/abc/def/` will all match `/abc`."}, "httpMethod": {"enum": ["GET", "HEAD", "POST", "PUT", "DELETE", "CONNECT", "OPTIONS", "TRACE", "PATCH"], "type": "string", "description": "(Optional) The HTTP method to match. Specify only when kind is HTTP."}, "httpHeaders": {"type": "array", "items": {"type": "object", "required": ["name", "value"], "properties": {"name": {"type": "string", "description": "(Required) The name of the HTTP Header to be matched. Must be exact."}, "value": {"type": "string", "description": "(Required) Value of HTTP Header to be matched."}}}, "description": "(Optional) HTTP headers to match. Specify only when kind is HTTP. Multiple match values are ANDed together. A request must match all the specified headers to match."}, "httpQueryParams": {"type": "array", "items": {"type": "object", "required": ["name", "value"], "properties": {"name": {"type": "string", "description": "(Required) Name of the HTTP query parameter to be matched. Specify only when kind is HTTP."}, "value": {"type": "string", "description": "(Required) Value of the HTTP query parameter to be matched."}}}, "description": "(Optional) HTTP query parameters to match. Specify only when kind is HTTP."}}}, "description": "(Required) Matches define conditions used for matching a request."}, "destinationContainer": {"type": "object", "required": ["resourceId", "containerName", "containerPort"], "properties": {"resourceId": {"type": "string", "description": "(Required) The Radius Container resource ID."}, "containerName": {"type": "string", "description": "(Required) The specific container to target within the Container resource."}, "containerPort": {"type": "integer", "description": "(Required) The port to target from the container."}}}}}, "description": "(Required) Rules define semantics for matching a network connection request based on conditions and forwarding the request to a Container."}, "listener": {"type": "object", "readOnly": true, "properties": {"port": {"type": "integer"}, "hostname": {"type": "string"}, "protocol": {"enum": ["HTTP", "HTTPS", "TLS", "TCP", "UDP"], "type": "string"}}, "description": "(Read Only) The Gateway Listener the route is assigned to."}, "hostnames": {"type": "array", "items": {"type": "string"}, "description": "(Optional) Use only when kind is HTTP or TLS. When HTTP, match against the HTTP Host header. When using TLS, match against the SNI attribute of TLS ClientHello message. Hostname may be preceded by a * wildcard."}, "application": {"type": "string", "description": "(Required) The Radius Application ID. `myApplication.id` for example."}, "connections": {"type": "object", "description": "Map of connection name to connection data.", "additionalProperties": {"type": "object", "required": ["source"], "properties": {"source": {"type": "string", "description": "Resource ID of the source resource for this connection."}, "disableDefaultEnvVars": {"type": "boolean", "description": "Disables the automatic injection of environment variables from the connected resource's properties."}}}}, "environment": {"type": "string", "description": "(Required) The Radius Environment ID. Typically set by the rad CLI. Typically value should be `environment`."}, "codeReference": {"type": "string", "description": "Optional URI to the source code of this resource type. ex: https://github.com/radius-project/radius/blob/4fab87e8127adf1db6f43b7029d5235fbe82c5c9/cmd/controller/main.go#L27"}}}}}, "description": "The Radius.Compute/routes Resource Type defines network routes for responding to external clients. Note that a Routes resource is not required for service-to-service communication. To use Routes, define a Container and ensure a `containerPort` is specified.\\n```\\nextension radius\\nparam environment string\\n\\nresource myApplication 'Radius.Core/applications@2025-08-01-preview' = { ... }\\n\\nresource myContainer 'Radius.Compute/containers@2025-08-01-preview' = {\\n  name: 'myContainer'\\n  properties: {\\n    environment: environment\\n    application: myApplication.id\\n    containers: {\\n      frontend: {\\n        image: 'frontend:1.25'\\n        ports: {\\n          web: {\\n            containerPort: 8080\\n          }\\n        }\\n      }\\n      accounts: {\\n        image: 'accounts:1.25'\\n        ports: {\\n          web: {\\n            containerPort: 8080\\n          }\\n        }\\n      }\\n    }\\n  }\\n}\\n```\\n\\nThen define a Routes resource.\\n```\\nresource ingressRule 'Radius.Compute/routes@2025-08-01-preview' = {\\n  name: 'ingressRule'\\n  properties: {\\n    application: myApplication.id\\n    environment: environment\\n    kind: 'HTTP'\\n    rules: [\\n      {\\n        matches: [\\n          {\\n            httpPath: '/'\\n          }\\n        ]\\n        destinationContainer: {\\n          resourceId: myContainer.id\\n          containerName: 'frontend'\\n          containerPort: myContainer.properties.containers.frontend.ports.web.containerPort\\n        }\\n      }\\n    ]\\n  }\\n}\\n```\\n\\nThe hostname is determined by the Recipe. \\n\\nMultiple rules can be included in Routes.\\n```\\nresource ingressRule 'Radius.Compute/routes@2025-08-01-preview' = {\\n  name: 'ingressRule'\\n  properties: {\\n    application: myApplication.id\\n    environment: environment\\n    kind: 'HTTP'\\n    rules: [\\n      {\\n        matches: [\\n          {\\n            httpPath: '/'\\n          }\\n        ]\\n        destinationContainer: {\\n          resourceId: myContainer.id\\n          containerName: 'frontend'\\n          containerPort: myContainer.properties.containers.frontend.ports.web.containerPort\\n        }\\n      }\\n      {\\n        matches: [\\n          {\\n            httpPath: '/accounts'\\n          }\\n        ]\\n        destinationContainer: {\\n          resourceId: myContainer.id\\n          containerName: 'accounts'\\n          containerPort: myContainer.properties.containers.accounts.ports.web.containerPort\\n        }\\n      }\\n    ]\\n  }\\n}\\n```\\n"}, "containers": {"apiVersions": {"2025-08-01-preview": {"schema": {"type": "object", "required": ["environment", "application", "containers"], "properties": {"volumes": {"type": "object", "description": "(Optional) List of volumes that can be mounted by a container.", "additionalProperties": {"type": "object", "properties": {"emptyDir": {"type": "object", "properties": {"medium": {"enum": ["disk", "memory"], "type": "string", "description": "(Optional) Set to `memory` for a tmpfs (RAM backed filesystem). Note that while tmpfs is very fast storage counts against the memory limit of the container."}}, "description": "(Optional) An empty directory."}, "secretName": {"type": "string", "description": "(Optional) The Radius Secret resource name."}, "persistentVolume": {"type": "object", "properties": {"accessMode": {"enum": ["ReadWriteOnce", "ReadOnlyMany", "ReadWriteMany"], "type": "string", "description": "(Optional) Set to `ReadWriteOnce` if no other Containers can mount in read/write mode. Set to `ReadOnlyMany` to enable other Containers to mount in read-only mode. Set to `ReadWriteMany` to allow multiple containers to mount in read/write mode. Assumed to be `ReadWriteOnce` if not specified."}, "resourceId": {"type": "string", "description": "(Required) The Radius PersistentVolume resource ID."}}, "description": "(Optional) Mount an existing Radius PersistentVolume resource."}}}}, "replicas": {"type": "integer", "description": "(Optional) The minimum number of replicas for the set of containers."}, "containers": {"type": "object", "additionalProperties": {"type": "object", "required": ["image"], "properties": {"env": {"type": "object", "description": "(Optional) Environment variables injected into the container.", "additionalProperties": {"type": "object", "properties": {"value": {"type": "string", "description": "(Optional) String value of the environment variable."}, "valueFrom": {"type": "object", "properties": {"secretKeyRef": {"type": "object", "properties": {"key": {"type": "string", "description": "(Optional) The key of the Radius Secrets resource. The value of the key will be used as the environment variable value."}, "secretName": {"type": "string", "description": "(Optional) The name of the Radius Secrets resource."}}, "description": "(Optional) Set the environment variable value based on a Radius Secrets resource."}}}}}}, "args": {"type": "array", "items": {"type": "string"}, "description": "(Optional) Arguments for the command. Overrides the container image CMD. `[\\"echo Hello\\", \\"&&\\", \\"echo World\\"]` for example."}, "image": {"type": "string", "description": "(Required) The container image. `ghcr.io/radius-project/samples/demo:latest` for example."}, "ports": {"type": "object", "description": "(Optional) Network ports exposed by the container. A network endpoint is created for each port. For L7 ingress create a Routes resource.", "additionalProperties": {"type": "object", "required": ["containerPort"], "properties": {"protocol": {"enum": ["TCP", "UDP"], "type": "string", "description": "(Optional) The protocol. If not specified, `TCP` is assumed."}, "containerPort": {"type": "integer", "description": "(Required) The network port the container is listening on. `443` for example."}}}}, "command": {"type": "array", "items": {"type": "string"}, "description": "(Optional) Command the container runs. Overrides the container image ENTRYPOINT. `[\\"/bin/sh\\", \\"-c\\"]` for example."}, "resources": {"type": "object", "properties": {"limits": {"type": "object", "properties": {"cpu": {"type": "string", "description": "(Optional) The maximum number of vCPUs which can be used by the container."}, "memoryInMib": {"type": "integer", "description": "(Optional) The maximum amount of memory which can be used by the container in MiB."}}, "description": "(Optional) Limits define the maximum amount of CPU or memory the container can consume."}, "requests": {"type": "object", "properties": {"cpu": {"type": "string", "description": "(Optional) The minimum number of vCPUs required by the container. `0.1` results in one tenth of a vCPU being reserved."}, "memoryInMib": {"type": "integer", "description": "(Optional) The minimum amount of memory required by the container in MiB. `1024` results in 1 GiB of memory being reserved."}}, "description": "(Optional) Requests define the minimum amount of CPU or memory that is required by the container."}}, "description": "(Optional) Compute resource requirements for the container."}, "workingDir": {"type": "string", "description": "(Optional) The working directory inside the container. `/usr/share` for example."}, "volumeMounts": {"type": "array", "items": {"type": "object", "required": ["volumeName", "mountPath"], "properties": {"mountPath": {"type": "string", "description": "(Required) The path to mount the volume in the container file system."}, "volumeName": {"type": "string", "description": "(Required) The name of the volume defined in Containers.properties.volumes."}}}, "description": "(Optional) Volumes to mount in the container."}, "initContainer": {"type": "boolean", "description": "(Optional) Set to true if container should run and succeed prior to other containers starting."}, "livenessProbe": {"type": "object", "properties": {"exec": {"type": "object", "required": ["command"], "properties": {"command": {"type": "array", "items": {"type": "string"}, "description": "(Required) The command to run inside the container. `[\\"cat\\", \\"/tmp/healthy\\"]` for example."}}, "description": "(Optional) An exec probe runs a command within a container. If the command succeeds and returns 0 the probe is healthy."}, "httpGet": {"type": "object", "required": ["path", "port"], "properties": {"path": {"type": "string", "description": "(Required) The path to access on the HTTP server."}, "port": {"type": "integer", "description": "(Required) The TCP port connect to on the container."}, "scheme": {"enum": ["http", "https"], "type": "string", "description": "(Optional) HTTP or HTTPS. Assumes HTTP is not specified."}, "httpHeaders": {"type": "array", "items": {"type": "object", "required": ["value"], "properties": {"value": {"type": "string", "description": "(Required) The header field value."}}}, "description": "(Optional) Custom HTTP headers to be included in the GET request."}}, "description": "(Optional) A httpGet probe performs a HTTP GET against the container on the specified port. If the HTTP server returns a code greater than or equal to 200 and less than 400 the probe is healthy."}, "tcpSocket": {"type": "object", "required": ["port"], "properties": {"port": {"type": "integer", "description": "(Required) The TCP port to connect to."}}, "description": "(Optional) A TCP socket probe establishes a TCP connection to the container on the specified port. If a connection is established the probe is healthy."}, "periodSeconds": {"type": "integer", "description": "(Optional) How often to perform the probe. Assumed to be 10 seconds if not specified."}, "timeoutSeconds": {"type": "integer", "description": "(Optional) Number of seconds after which the probe times out. Assumed to be 1 second if not specified."}, "failureThreshold": {"type": "integer", "description": "(Optional) Minimum consecutive failures for the probe to be considered failed after having succeeded. Assumed to be 3 if not specified."}, "successThreshold": {"type": "integer", "description": "(Optional) Minimum consecutive successes for the probe to be considered successful after having failed. Assumed to be 1 if not specified."}, "initialDelaySeconds": {"type": "integer", "description": "(Optional) Number of seconds after the container has started before probes are initiated."}, "terminationGracePeriodSeconds": {"type": "integer", "description": "(Optional) Number of seconds the container needs to terminate gracefully upon probe failure. The grace period amount of time between when a container is sent a termination signal and the time when the processes are forcibly halted with a kill signal."}}, "description": "(Optional) A liveness probe defines a check (a probe) to determine if a container is healthy."}, "readinessProbe": {"type": "object", "properties": {"exec": {"type": "object", "required": ["command"], "properties": {"command": {"type": "array", "items": {"type": "string", "description": "(Required) The command to run inside the container. `[\\"cat\\", \\"/tmp/healthy\\"]` for example."}}}, "description": "(Optional) An exec probe runs a command within a container. If the command succeeds and returns 0 the probe is healthy."}, "httpGet": {"type": "object", "required": ["path", "port"], "properties": {"path": {"type": "string", "description": "(Required) The path to access on the HTTP server."}, "port": {"type": "integer", "description": "(Required) The TCP port connect to on the container."}, "scheme": {"enum": ["http", "https"], "type": "string", "description": "(Optional) HTTP or HTTPS. Assumes HTTP is not specified."}, "httpHeaders": {"type": "array", "items": {"type": "object", "required": ["value"], "properties": {"value": {"type": "string", "description": "(Required) The header field value."}}}, "description": "(Optional) Custom HTTP headers to be included in the GET request."}}, "description": "(Optional) A httpGet probe performs a HTTP GET against the container on the specified port. If the HTTP server returns a code greater than or equal to 200 and less than 400 the probe is healthy."}, "tcpSocket": {"type": "object", "required": ["port"], "properties": {"port": {"type": "integer", "description": "(Required) The TCP port to connect to."}}, "description": "(Optional) A TCP socket probe establishes a TCP connection to the container on the specified port. If a connection is established the probe is healthy."}, "periodSeconds": {"type": "integer", "description": "(Optional) How often to perform the probe. Assumed to be 10 seconds if not specified."}, "timeoutSeconds": {"type": "integer", "description": "(Optional) Number of seconds after which the probe times out. Assumed to be 1 second if not specified."}, "failureThreshold": {"type": "integer", "description": "(Optional) Minimum consecutive failures for the probe to be considered failed after having succeeded. Assumed to be 3 if not specified."}, "successThreshold": {"type": "integer", "description": "(Optional) Minimum consecutive successes for the probe to be considered successful after having failed. Assumed to be 1 if not specified."}, "initialDelaySeconds": {"type": "integer", "description": "(Optional) Number of seconds after the container has started before probes are initiated."}, "terminationGracePeriodSeconds": {"type": "integer", "description": "(Optional) Number of seconds the container needs to terminate gracefully upon probe failure. The grace period amount of time between when a container is sent a termination signal and the time when the processes are forcibly halted with a kill signal."}}, "description": "(Optional) A readiness probe defines a check (a probe) to determine when a container is ready to begin accepting traffic."}}}}, "extensions": {"type": "object", "properties": {"daprSidecar": {"type": "object", "properties": {"appId": {"type": "string", "description": "(Optional) The unique ID of the Dapr application. Used for service discovery, state encapsulation and the pub/sub consumer ID."}, "config": {"type": "string", "description": "(Optional) The Dapr Configuration resource name."}, "appPort": {"type": "integer", "description": "(Optional) The port your application is listening on."}}, "description": "(Optional) When set the daprSidecar container is configured."}}, "description": "(Optional) Properties for additional functionality. daprSidecar is the only available option."}, "application": {"type": "string", "description": "(Required) The Radius Application ID. `myApplication.id` for example."}, "autoScaling": {"type": "object", "required": ["metrics"], "properties": {"metrics": {"type": "array", "items": {"type": "object", "required": ["kind", "target"], "properties": {"kind": {"enum": ["cpu", "memory", "custom"], "type": "string", "description": "(Required) The metric to measure."}, "target": {"type": "object", "properties": {"value": {"type": "integer", "description": "(Optional) The absolute value of the metric as a quantity."}, "averageValue": {"type": "integer", "description": "(Optional) The average value of the metric as a quantity."}, "averageUtilization": {"type": "integer", "description": "(Optional) The average CPU or memory utilization across all containers expressed as a percentage. Kind must be CPU or memory."}}, "description": "(Required) When the metric exceeds the target value specified, autoscaling is triggered. Only one target value can be specified dependent upon the type."}, "customMetric": {"type": "string", "description": "(Optional) The custom metric exposed by the application. Implementation specific. See platform engineer for further guidance."}}}, "description": "(Required) The metric to measure and target used to autoscale."}, "maxReplicas": {"type": "integer", "description": "(Optional) The maximum number of replicas for the autoscaler."}}}, "connections": {"type": "object", "description": "(Optional) Map of resources this container is dependent upon. `db: { source: db.id } for example.", "additionalProperties": {"type": "object", "required": ["source"], "properties": {"source": {"type": "string", "description": "(Required) The resource ID of the resource this container is dependent upon."}, "disableDefaultEnvVars": {"type": "boolean", "description": "(Optional) Disables the automatic injection of environment variables from connected resource properties."}}}}, "environment": {"type": "string", "description": "(Required) The Radius Environment ID. Typically set by the rad CLI. Typically value should be `environment`."}, "codeReference": {"type": "string", "description": "Optional URI to the source code of this resource type. ex: https://github.com/radius-project/radius/blob/4fab87e8127adf1db6f43b7029d5235fbe82c5c9/cmd/controller/main.go#L27"}, "restartPolicy": {"enum": ["Always", "OnFailure", "Never"], "type": "string", "description": "(Optional) Defines how a containers behave when they terminate. `Always` will restart containers regardless of their exit status. `OnFailure` will restart containers if they return a non-zero exit code."}, "platformOptions": {"type": "object", "description": "(Optional) If enabled by the platform engineer, properties to be passed to the Recipe for the specified platform.", "additionalProperties": {"type": "any", "description": "(Required) Platform-specific properties."}}}}}}, "description": "The Radius.Compute/containers Resource Type is the primary resource type for running one or more containers. It is always part of a Radius Application. To deploy a Container add a resource to the application definition Bicep file.\\n\\n```\\nextension radius\\nparam environment string \\n\\nresource myApplication 'Radius.Core/applications@2025-08-01-preview' = { ... }\\n\\nresource myContainer 'Radius.Compute/containers@2025-08-01-preview' = {\\n  name: 'myContainer'\\n  properties: {\\n    environment: environment\\n    application: myApplication.id\\n    containers: {\\n      demo: {\\n        image: 'ghcr.io/radius-project/samples/demo:latest'\\n      }\\n    }\\n  }\\n}\\n```\\n\\nBy default, Containers deploys to Kubernetes. In this case, a Kubernetes Deployment named myContainer is deployed which includes a Pod named myContainer. Your Radius environment may deploy to other container platforms such as Azure Container Instances. \\n\\nTo accept network connections, expose a port on the container.\\n\\n```\\nresource myContainer 'Radius.Compute/containers@2025-08-01-preview' = {\\n  name: 'myContainer'\\n  properties: {\\n    environment: environment\\n    application: myApplication.id\\n    containers: {\\n      demo: {\\n        image: 'ghcr.io/radius-project/samples/demo:latest'\\n        ports: {\\n          web: {\\n            containerPort: 3000\\n          }\\n        }\\n      }\\n    }\\n  }\\n}\\n```\\n\\nWhen a port is included, a Kubernetes Service named demo with the type ClusterIP is created.\\n\\nTo create a emphemeral emptyDir shared between two containers add a Containers.properties.volumes.\\n\\n```\\nresource myContainer 'Radius.Compute/containers@2025-08-01-preview' = {\\n  name: 'myContainer'\\n  properties: {\\n    environment: environment\\n    application: myApplication.id\\n    containers: {\\n      frontend: {\\n        image: 'frontend:latest'\\n        volumeMounts: [\\n          {\\n            volumeName: 'shared'\\n            mountPath: '/var/shared' \\n          }\\n        ]\\n      }\\n      backend: {\\n        image: 'backend:latest'\\n        volumeMounts: [\\n          {\\n            volumeName: 'shared'\\n            mountPath: '/var/shared' \\n          }\\n        ]\\n      }\\n    }\\n    volumes: {\\n      shared: {\\n        emptyDir: {}\\n      }\\n    }\\n  }\\n}\\n```\\n\\nTo mount a persistent volume or secret see the PersistentVolumes and Secrets Resource Types.\\n"}, "containerImages": {"apiVersions": {"2025-08-01-preview": {"schema": {"type": "object", "required": ["environment", "application", "build"], "properties": {"tag": {"type": "string", "description": "(Optional) Tag for the produced image. When unset, the recipe computes a content-addressable digest (`sha256-<hash>`) from the build inputs. For git sources, pin to a commit SHA or immutable tag (e.g. `?ref=<sha>`) so that the computed tag is genuinely content-addressable; with a moving ref like `?ref=main`, the computed tag does not change when the upstream branch advances."}, "build": {"type": "object", "required": ["source"], "properties": {"args": {"type": "object", "description": "(Optional) Map of `--build-arg` values passed to the build, e.g. `{ VERSION: 'v1.2.3' }`. Argument names must match `[A-Za-z_][A-Za-z0-9_]*`. Values must not contain shell metacharacters.", "additionalProperties": {"type": "string"}}, "source": {"type": "string", "description": "(Required) Source location for the build. Either a git URL of the form `git::https://...` (BuildKit clones the repo inside the cluster) or a local filesystem path to a directory containing the build context. For git URLs, the subdirectory is selected via the go-getter `//<subdir>` segment and the ref via the `?ref=<branch-or-sha>` query parameter, in that order. Example, `git::https://github.com/myorg/myapp.git//frontend?ref=v1.2.3`."}, "platforms": {"type": "array", "items": {"type": "string"}, "description": "(Optional) Target platforms to build for (e.g. `[\\"linux/amd64\\"]`, `[\\"linux/amd64\\", \\"linux/arm64\\"]`). When omitted, defaults to `[\\"linux/amd64\\", \\"linux/arm64\\"]`. Multi-platform builds use cross-compilation; the Dockerfile must use `FROM --platform=$BUILDPLATFORM` and `TARGETARCH`.\\n"}, "dockerfile": {"type": "string", "description": "(Optional) Path to the Dockerfile relative to the build source. Defaults to `Dockerfile`."}}, "description": "(Required) Build configuration for the container image."}, "application": {"type": "string", "description": "(Required) The Radius Application ID. `myApplication.id` for example."}, "connections": {"type": "object", "description": "Map of connection name to connection data.", "additionalProperties": {"type": "object", "required": ["source"], "properties": {"source": {"type": "string", "description": "Resource ID of the source resource for this connection."}, "disableDefaultEnvVars": {"type": "boolean", "description": "Disables the automatic injection of environment variables from the connected resource's properties."}}}}, "environment": {"type": "string", "description": "(Required) The Radius Environment ID. Typically set by the rad CLI. Typical value should be `environment`."}, "codeReference": {"type": "string", "description": "Optional URI to the source code of this resource type. ex: https://github.com/radius-project/radius/blob/4fab87e8127adf1db6f43b7029d5235fbe82c5c9/cmd/controller/main.go#L27"}, "imageReference": {"type": "string", "readOnly": true, "description": "(Read Only) The full image reference produced by the recipe in the form `<registry>/<resource-name>:<tag>`. Reference this from `Radius.Compute/containers` to consume the built image."}}}}}, "description": "The Radius.Compute/containerImages Resource Type builds a container image from source and pushes it to an OCI registry. Builds run inside the Radius control plane.\\n\\nTo use a containerImages resource in your application, add a containerImages resource to the application definition Bicep file, then reference the `containerImages.imageReference` property in the containers resource. For example:\\n\\n```bicep\\nextension radius\\n\\nparam environment string\\n\\nresource myApp 'Radius.Core/applications@2025-08-01-preview' = {\\n  name: 'myApp'\\n  properties: {\\n    environment: environment\\n  }\\n}\\n\\nresource myImage 'Radius.Compute/containerImages@2025-08-01-preview' = {\\n  name: 'myImage'\\n  properties: {\\n    environment: environment\\n    application: myApp.id\\n    tag:         'v1.2.3'\\n    build: {\\n      source: 'git::https://github.com/myorg/myapp.git//frontend?ref=v1.2.3'\\n    }\\n  }\\n}\\n\\nresource myContainer 'Radius.Compute/containers@2025-08-01-preview' = {\\n  name: 'myContainer'\\n  properties: {\\n    environment: environment\\n    application: myApp.id\\n    containers: {\\n      app: {\\n        image: myImage.properties.imageReference\\n        ports: {\\n          web: {\\n            containerPort: 3000\\n          }\\n        }\\n      }\\n    }\\n  }\\n}\\n```\\n\\nMulti-architecture builds (e.g. `platforms: [\\"linux/amd64\\", \\"linux/arm64\\"]`) require a Dockerfile that supports cross-compilation via `FROM --platform=$BUILDPLATFORM` and `TARGETARCH`. Dockerfiles that execute target-arch binaries during the build will fail with `exec format error`. There is no QEMU/binfmt fallback in this design.\\n"}, "persistentVolumes": {"apiVersions": {"2025-08-01-preview": {"schema": {"type": "object", "required": ["environment", "sizeInGib"], "properties": {"sizeInGib": {"type": "integer", "description": "(Required) The size of the volume in gibibytes. `1` represents 1024 MiB."}, "application": {"type": "string", "description": "(Optional) The Radius Application ID. `myApplication.id` for example."}, "connections": {"type": "object", "description": "Map of connection name to connection data.", "additionalProperties": {"type": "object", "required": ["source"], "properties": {"source": {"type": "string", "description": "Resource ID of the source resource for this connection."}, "disableDefaultEnvVars": {"type": "boolean", "description": "Disables the automatic injection of environment variables from the connected resource's properties."}}}}, "environment": {"type": "string", "description": "(Required) The Radius Environment ID. Typically set by the rad CLI. Typically value should be `environment`."}, "codeReference": {"type": "string", "description": "Optional URI to the source code of this resource type. ex: https://github.com/radius-project/radius/blob/4fab87e8127adf1db6f43b7029d5235fbe82c5c9/cmd/controller/main.go#L27"}, "allowedAccessModes": {"enum": ["ReadWriteOnce", "ReadOnlyMany", "ReadWriteMany"], "type": "string", "description": "(Optional) The access modes which are permitted to be requested by a Container. Assumed to be all modes if not specified."}}}}}, "description": "The Radius.Compute/persistentVolumes Resource Type represents a persistent storage volume. A PersistentVolume can be referenced in the volumes property of a Container. \\nTo deploy, first add a PersistentVolume resource to the application definition Bicep file.\\n```\\nextension radius\\nparam environment string \\n\\nresource myApplication 'Radius.Core/applications@2025-08-01-preview' = { ... }\\n\\nresource myPersistentVolume 'Radius.Compute/persistentVolumes@2025-08-01-preview' = {\\n  name: 'myPersistentVolume'\\n  properties: {\\n    environment: environment\\n    application: myApplication.id\\n    sizeInGib: 1\\n  }\\n}\\n```\\n\\nThen reference the PersistentVolume by ID in the volumes property of the Container. Finally, set the mountPath in the container referencing the volumeName.\\n```\\nresource myContainer 'Radius.Compute/containers@2025-08-01-preview' = {\\n  name: 'myContainer'\\n  properties: {\\n    environment: environment\\n    application: myApplication.id\\n    containers: {\\n      demo: {\\n        image: 'ghcr.io/radius-project/samples/demo:latest'\\n        volumeMounts: [\\n          {\\n          volumeName: 'data'\\n          mountPath: '/app/data'\\n          } \\n        ] \\n      }\\n    }\\n    volumes: {\\n      data: {\\n        persistentVolume: {\\n          resourceId: myPersistentVolume.id\\n        }\\n      }\\n    }\\n  }\\n}\\n```\\n\\nPersistentVolumes may be shared across multiple Containers. To mount an existing PersistentVolume in read-only mode, reference the PersistentVolume by name using the `existing` Bicep keyword. For example:\\n```\\nresource existingPersistentVolume 'Radius.Compute/persistentVolumes@2025-08-01-preview' existing = {\\n  name: 'existingPersistentVolume'\\n}\\n```\\n\\nThen add the existing PersistentVolume to the volumes property of a Container with accessMode set to `ReadOnlyMany`.\\n```\\nresource myContainer 'Radius.Compute/containers@2025-08-01-preview' = {\\n  name: 'myContainer'\\n  properties: {\\n    environment: environment\\n    application: myApplication.id\\n    containers: {\\n      demo: {\\n        image: 'ghcr.io/radius-project/samples/demo:latest'\\n        volumeMounts: [\\n          {\\n            volumeName: 'readOnlyData'\\n            mountPath: '/app/data' \\n          }\\n        ]\\n      }\\n    }\\n    volumes: {\\n      readOnlyData: {\\n        persistentVolume: {\\n          resourceId: existingPersistentVolume.id\\n          accessMode: 'ReadOnlyMany'\\n        }\\n      }\\n    }\\n  }\\n}\\n```\\n\\nA PersistentVolume may be shared between multiple Containers in read/write mode if the PersistentVolume was created with `accessMode: ReadWriteMany` and the volume is set to ReadWriteMany as well. Note that not all infrastructures support this mode.\\n"}}}, "systemData": {}, "createdApiVersion": ""}
