/planes/radius/local/providers/system.resources/resourceproviders/radius.security/resourcetypes/secrets/	/planes/radius/local/providers/System.Resources/resourceProviders/Radius.Security/resourceTypes/secrets	/system.resources/resourceproviders/resourcetypes/	/planes/radius/local/	/system.resources/resourceproviders/radius.security/resourcetypes/secrets/	32-2fabd6ebbe37bfac6ca367eb625695febc57adf818cab1131429fc21568388ba	2026-07-01 21:18:08.78149+00	{"id": "/planes/radius/local/providers/System.Resources/resourceProviders/Radius.Security/resourceTypes/secrets", "name": "secrets", "type": "System.Resources/resourceProviders/resourceTypes", "location": "", "tenantId": "", "properties": {"description": "The Radius.Security/secrets Resource Type stores sensitive data such as tokens, passwords, keys, and certificates. To create a new Secret, start by adding parameter to your application definition decorated with `@secure()`. Then add a `secrets` resource. Never include secret values in an application definition. \\n```\\n  extension radius\\n\\n  @description('The Radius environment ID')\\n  param environment string\\n\\n  @secure()\\n  param password string\\n\\n  resource myApplication 'Radius.Core/applications@2025-08-01-preview' = { \\n    name: 'my-app'\\n    properties: {\\n      environment: environment\\n    }\\n  }\\n\\n  // Passing password as a parameter to `rad deploy`\\n  // password=$(openssl rand -hex 16) \\n  // rad deploy app.bicep -p password=$password\\n  resource dbCredentials 'Radius.Security/secrets@2025-08-01-preview' = {\\n    name: 'db-creds'\\n    properties: {\\n      environment: environment\\n      application: myApplication.id\\n      data: {\\n        username: {\\n          value: 'admin'\\n        }\\n        password: {\\n          // From password parameter passed in via CLI. \\n          value: password\\n        }\\n      }\\n    }\\n  }\\n  ```\\nWhen deploying the application, specify the secret value as a command-line parameter. It is recommended to use a password generator such as `openssl` or equivalent. For example, `rad deploy app.bicep -p password=$(openssl rand -hex 16)`.\\nFor details on how to use the secret with another resource such as a container or database, see the documentation for those resource types.    \\n", "defaultApiVersion": null}, "systemData": {}, "createdApiVersion": "", "provisioningState": "Succeeded"}
