/planes/radius/local/providers/system.resources/resourceproviders/radius.data/resourcetypes/mysqldatabases/	/planes/radius/local/providers/System.Resources/resourceProviders/Radius.Data/resourceTypes/mySqlDatabases	/system.resources/resourceproviders/resourcetypes/	/planes/radius/local/	/system.resources/resourceproviders/radius.data/resourcetypes/mysqldatabases/	32-5a7d2d25f53d5c180529b351f8a638ed200bf0bd6035df4fb4aa039f3c330f45	2026-07-01 21:18:08.783986+00	{"id": "/planes/radius/local/providers/System.Resources/resourceProviders/Radius.Data/resourceTypes/mySqlDatabases", "name": "mySqlDatabases", "type": "System.Resources/resourceProviders/resourceTypes", "location": "", "tenantId": "", "properties": {"description": "The Radius.Data/mySqlDatabases Resource Type deploys a MySQL database. To deploy a new MySQL database, first add a secret resource with the database credentials to the application definition Bicep file, then add a mySqlDatabases resource referencing the secret name.\\n```\\nresource mysql 'Radius.Data/mySqlDatabases@2025-08-01-preview' = {\\n  name: 'mysql'\\n  properties: {\\n    environment: environment\\n    application: myApplication.id\\n    secretName: dbCredentials.name\\n  }\\n}\\n\\nresource dbCredentials 'Radius.Security/secrets@2025-08-01-preview' = {\\n  name: 'db-creds'\\n  properties: {\\n    environment: environment\\n    application: myApplication.id\\n    data: {\\n      USERNAME: {\\n        value: 'admin'\\n      }\\n      PASSWORD: {\\n        # From password parameter passed in via CLI\\n        value: password\\n      }\\n    }\\n  }\\n}\\n```\\n\\nWhen deploying the application definition, provide the database password value as a parameter. It is recommended to use a password generator such as `openssl` or equivalent. For example, `rad deploy app.bicep -p password=$(openssl rand -hex 16)`.\\n\\nTo connect your container to the database, create a connection from the Container resource to the database as shown below. \\n```\\nresource myApplication 'Radius.Core/Applications@2025-08-01-preview' = { ... }\\n\\nresource frontend 'Radius.Compute/containers@2025-08-01-preview' = {\\n  name: 'frontend'\\n  properties: {\\n    application: myApplication.id\\n    environment: environment\\n    container: {\\n      image: 'frontend:1.25'\\n      ports: {\\n        web: {\\n          containerPort: 8080\\n        }\\n      }\\n    }\\n    connections: {\\n      mysqldb: {\\n        source: database.id\\n      }\\n    }\\n  }\\n}\\n```\\n\\nThe connection automatically injects environment variables into the container for all properties from the database. The environment variables are named `CONNECTION_<CONNECTION-NAME>_<PROPERTY-NAME>`. In this example, the connection name is `mysqldb` so the environment variables will be:\\n\\n- CONNECTION_MYSQLDB_DATABASE\\n- CONNECTION_MYSQLDB_HOST\\n- CONNECTION_MYSQLDB_PORT\\n", "defaultApiVersion": null}, "systemData": {}, "createdApiVersion": "", "provisioningState": "Succeeded"}
/planes/radius/local/providers/system.resources/resourceproviders/radius.data/resourcetypes/mysqldatabases/apiversions/2025-08-01-preview/	/planes/radius/local/providers/System.Resources/resourceProviders/Radius.Data/resourceTypes/mySqlDatabases/apiVersions/2025-08-01-preview	/system.resources/resourceproviders/resourcetypes/apiversions/	/planes/radius/local/	/system.resources/resourceproviders/radius.data/resourcetypes/mysqldatabases/apiversions/2025-08-01-preview/	32-9ae735f9a3bd316485ed8b6e44cd6cde147add14d47ea09e65a569176947f449	2026-07-01 21:18:08.78456+00	{"id": "/planes/radius/local/providers/System.Resources/resourceProviders/Radius.Data/resourceTypes/mySqlDatabases/apiVersions/2025-08-01-preview", "name": "2025-08-01-preview", "type": "System.Resources/resourceProviders/resourceTypes/apiVersions", "location": "", "tenantId": "", "properties": {"Schema": {"type": "object", "required": ["environment", "secretName"], "properties": {"host": {"type": "string", "readOnly": true, "description": "(Read-only) The host name used to connect to the database."}, "port": {"type": "integer", "readOnly": true, "description": "(Read-only) The port number used to connect to the database."}, "version": {"enum": ["5.7", "8.0", "8.4"], "type": "string", "description": "(Optional) The major MySQL server version in the X.Y format. Assumed to be 8.4 if not specified."}, "database": {"type": "string", "description": "(Optional) The name of the database. Defaults to `mysql_db` if not provided."}, "secretName": {"type": "string", "description": "(Required) The name of the secret containing the database credentials."}, "application": {"type": "string", "description": "(Optional) The Radius Application ID. `myApplication.id` for example."}, "connections": {"type": "object", "description": "Map of connection name to connection data.", "additionalProperties": {"type": "object", "required": ["source"], "properties": {"source": {"type": "string", "description": "Resource ID of the source resource for this connection."}, "disableDefaultEnvVars": {"type": "boolean", "description": "Disables the automatic injection of environment variables from the connected resource's properties."}}}}, "environment": {"type": "string", "description": "(Required) The Radius EnvironmentID. Typically set by the rad CLI. Typically value should be `environment`"}, "codeReference": {"type": "string", "description": "Optional URI to the source code of this resource type. ex: https://github.com/radius-project/radius/blob/4fab87e8127adf1db6f43b7029d5235fbe82c5c9/cmd/controller/main.go#L27"}}}}, "systemData": {}, "createdApiVersion": "", "provisioningState": "Succeeded"}
