/planes/radius/local/providers/system.resources/resourceproviders/radius.compute/resourcetypes/containerimages/	/planes/radius/local/providers/System.Resources/resourceproviders/Radius.Compute/resourcetypes/containerImages	/system.resources/resourceproviders/resourcetypes/	/planes/radius/local/	/system.resources/resourceproviders/radius.compute/resourcetypes/containerimages/	32-adf8d37ffe76dc0b6b054190629fea98d76071df9a4fa28586224bfcedef1c4e	2026-07-01 21:19:56.523055+00	{"id": "/planes/radius/local/providers/System.Resources/resourceproviders/Radius.Compute/resourcetypes/containerImages", "name": "containerImages", "type": "System.Resources/resourceproviders/resourcetypes", "location": "global", "tenantId": "", "properties": {"description": "The Radius.Compute/containerImages Resource Type builds a container image from source and pushes it to an OCI registry. Builds run inside the Radius control plane.\\n\\nTo use a containerImages resource in your application, add a containerImages resource to the application definition Bicep file, then reference the `containerImages.imageReference` property in the containers resource. For example:\\n\\n```bicep\\nextension radius\\n\\nparam environment string\\n\\nresource myApp 'Radius.Core/applications@2025-08-01-preview' = {\\n  name: 'myApp'\\n  properties: {\\n    environment: environment\\n  }\\n}\\n\\nresource myImage 'Radius.Compute/containerImages@2025-08-01-preview' = {\\n  name: 'myImage'\\n  properties: {\\n    environment: environment\\n    application: myApp.id\\n    tag:         'v1.2.3'\\n    build: {\\n      source: 'git::https://github.com/myorg/myapp.git//frontend?ref=v1.2.3'\\n    }\\n  }\\n}\\n\\nresource myContainer 'Radius.Compute/containers@2025-08-01-preview' = {\\n  name: 'myContainer'\\n  properties: {\\n    environment: environment\\n    application: myApp.id\\n    containers: {\\n      app: {\\n        image: myImage.properties.imageReference\\n        ports: {\\n          web: {\\n            containerPort: 3000\\n          }\\n        }\\n      }\\n    }\\n  }\\n}\\n```\\n\\nMulti-architecture builds (e.g. `platforms: [\\"linux/amd64\\", \\"linux/arm64\\"]`) require a Dockerfile that supports cross-compilation via `FROM --platform=$BUILDPLATFORM` and `TARGETARCH`. Dockerfiles that execute target-arch binaries during the build will fail with `exec format error`. There is no QEMU/binfmt fallback in this design.\\n", "defaultApiVersion": null}, "systemData": {}, "createdApiVersion": "2023-10-01-preview", "provisioningState": "Succeeded", "updatedApiVersion": "2023-10-01-preview"}
/planes/radius/local/providers/system.resources/resourceproviders/radius.compute/resourcetypes/containerimages/apiversions/2025-08-01-preview/	/planes/radius/local/providers/System.Resources/resourceproviders/Radius.Compute/resourcetypes/containerImages/apiversions/2025-08-01-preview	/system.resources/resourceproviders/resourcetypes/apiversions/	/planes/radius/local/	/system.resources/resourceproviders/radius.compute/resourcetypes/containerimages/apiversions/2025-08-01-preview/	32-a2011679bc554d3d649150dcd9f255da8fb1d71eb2c2bef0cd6129a3db7ab028	2026-07-01 21:19:57.539337+00	{"id": "/planes/radius/local/providers/System.Resources/resourceproviders/Radius.Compute/resourcetypes/containerImages/apiversions/2025-08-01-preview", "name": "2025-08-01-preview", "type": "System.Resources/resourceproviders/resourcetypes/apiversions", "location": "global", "tenantId": "", "properties": {"Schema": {"type": "object", "required": ["environment", "application", "build"], "properties": {"tag": {"type": "string", "description": "(Optional) Tag for the produced image. When unset, the recipe computes a content-addressable digest (`sha256-<hash>`) from the build inputs. For git sources, pin to a commit SHA or immutable tag (e.g. `?ref=<sha>`) so that the computed tag is genuinely content-addressable; with a moving ref like `?ref=main`, the computed tag does not change when the upstream branch advances."}, "build": {"type": "object", "required": ["source"], "properties": {"args": {"type": "object", "description": "(Optional) Map of `--build-arg` values passed to the build, e.g. `{ VERSION: 'v1.2.3' }`. Argument names must match `[A-Za-z_][A-Za-z0-9_]*`. Values must not contain shell metacharacters.", "additionalProperties": {"type": "string"}}, "source": {"type": "string", "description": "(Required) Source location for the build. Either a git URL of the form `git::https://...` (BuildKit clones the repo inside the cluster) or a local filesystem path to a directory containing the build context. For git URLs, the subdirectory is selected via the go-getter `//<subdir>` segment and the ref via the `?ref=<branch-or-sha>` query parameter, in that order. Example, `git::https://github.com/myorg/myapp.git//frontend?ref=v1.2.3`."}, "platforms": {"type": "array", "items": {"type": "string"}, "description": "(Optional) Target platforms to build for (e.g. `[\\"linux/amd64\\"]`, `[\\"linux/amd64\\", \\"linux/arm64\\"]`). When omitted, defaults to `[\\"linux/amd64\\", \\"linux/arm64\\"]`. Multi-platform builds use cross-compilation; the Dockerfile must use `FROM --platform=$BUILDPLATFORM` and `TARGETARCH`.\\n"}, "dockerfile": {"type": "string", "description": "(Optional) Path to the Dockerfile relative to the build source. Defaults to `Dockerfile`."}}, "description": "(Required) Build configuration for the container image."}, "application": {"type": "string", "description": "(Required) The Radius Application ID. `myApplication.id` for example."}, "connections": {"type": "object", "description": "Map of connection name to connection data.", "additionalProperties": {"type": "object", "required": ["source"], "properties": {"source": {"type": "string", "description": "Resource ID of the source resource for this connection."}, "disableDefaultEnvVars": {"type": "boolean", "description": "Disables the automatic injection of environment variables from the connected resource's properties."}}}}, "environment": {"type": "string", "description": "(Required) The Radius Environment ID. Typically set by the rad CLI. Typical value should be `environment`."}, "codeReference": {"type": "string", "description": "Optional URI to the source code of this resource type. ex: https://github.com/radius-project/radius/blob/4fab87e8127adf1db6f43b7029d5235fbe82c5c9/cmd/controller/main.go#L27"}, "imageReference": {"type": "string", "readOnly": true, "description": "(Read Only) The full image reference produced by the recipe in the form `<registry>/<resource-name>:<tag>`. Reference this from `Radius.Compute/containers` to consume the built image."}}}}, "systemData": {}, "createdApiVersion": "2023-10-01-preview", "provisioningState": "Succeeded", "updatedApiVersion": "2023-10-01-preview"}
